#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
using namespace std;
inline int read()
{
	int res=0,flag=1;char ch=getchar();
	while(ch<'0'||ch>'9')flag-=(ch=='-')<<1,ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return res*flag;
}
const int N=1e5+22,M=2e5+22,K=25,INF=0x7fffffff;
struct Graph{int head[N],des[M],val[M],nxt[M],cnt;//
	inline void ins(int x,int y,int z){des[++cnt]=y;val[cnt]=z;nxt[cnt]=head[x];head[x]=cnt;}}a;
double dp[N][2],sum;int n,siz[N],nfa[N],cir[K],p,dl[K],dr[K];bool vis[N],isc[N];
//inline void dfs0(int u,int fa){siz[u]=1;grep(a,u,i)if(i!=fa)dfs0(v,i^1),siz[u]+=siz[v];}
int dfs0(int u,int fa)
{
	int res=u;vis[u]=1;bool flag=0;grep(a,u,T)
	{
		int v=a.des[T];if(T==fa)continue;
		if(vis[v]){if(!flag)res=v,flag=1,isc[cir[++p]=v]=1;continue;}
		int tmp=dfs0(v,T^1);if(tmp!=v){res=tmp;isc[cir[++p]=v]=1;flag=1;}
	}return res;
}
void dfs1(int u,int fa)
{
	siz[u]=0;dp[u][0]=0;grep(a,u,T)
	{
		int v=a.des[T];if(T==fa||isc[v])continue;dfs1(v,T^1);
		siz[u]++;dp[u][0]+=dp[v][0]+a.val[T];nfa[v]=1;
	}
//	printf("%d %.2lf\n",u,dp[u][0]);
	dp[u][0]=siz[u]?dp[u][0]/(1.0*siz[u]):0.0;
}
void dfs2(int u,int fa)
{
//	printf("%d\n",u);
	grep(a,u,T)
	{
		int v=a.des[T];if(T==fa||isc[v])continue;
		dp[v][1]=a.val[T]+((nfa[u]+siz[u]-1)?(dp[u][1]*nfa[u]+dp[u][0]*siz[u]-dp[v][0]-a.val[T])/(nfa[u]+siz[u]-1):0);
		dfs2(v,T^1);
	}
}
inline int dfs3(int u,int v){grep(a,u,i){if(a.des[i]==v)return a.val[i];}return 0;}
inline int pre(int k){return k==p?1:k+1;}inline int suc(int k){return k==1?p:k-1;}
inline void Solve()
{
	dfs0(1,0);rep(1,p,i)nfa[cir[i]]=2,dl[i]=dr[i+1]=dfs3(cir[i],cir[i+1]);dr[1]=dl[p]=dfs3(cir[1],cir[p]);
//	rep(1,p,i)printf("%d ",cir[i]);puts(""); 
	rep(1,p,i)dfs1(cir[i],0);//rep(1,n,i)printf("%d ",siz[i]);puts("");
	rep(1,p,i)
	{
		int u=cir[i];double P=0.5;
		for(int j=suc(i);j!=i;j=suc(j))
		{
			int v=cir[j];if(suc(j)==i)dp[u][1]+=P*(dl[j]+dp[v][0]);
			else dp[u][1]+=P*(dl[j]+dp[v][0]*siz[v]/(siz[v]+1));P/=(siz[v]+1);
		}
		P=0.5;for(int j=pre(i);j!=i;j=pre(j))
		{
			int v=cir[j];if(pre(j)==i)dp[u][1]+=P*(dr[j]+dp[v][0]);
			else dp[u][1]+=P*(dr[j]+dp[v][0]*siz[v]/(siz[v]+1));P/=(siz[v]+1);
		}
		dfs2(u,0);
	}
//	rep(1,n,i)printf("%.0lf ",dp[i][1]);puts("");
}
int main()
{
	a.cnt=1;n=read();int m=read();bool typ=(n-m)^1;
	rep(1,m,i){int x=read(),y=read(),z=read();a.ins(x,y,z);a.ins(y,x,z);}
	if(!typ)dfs1(1,0),dfs2(1,0);else Solve();
	rep(1,n,i)sum+=1.0*(dp[i][0]*siz[i]+dp[i][1]*nfa[i])/(siz[i]+nfa[i]);
	printf("%.5lf",sum/n);return 0;
}
